def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    symbol = "AAPL"
    end_date_for_history = "2024-07-20"

    # Step 1: Get the latest quote for AAPL to find its most recent closing price
    execution_log.append(f"Step 1: Fetching latest quote for {symbol} using twelvedata_GetQuote.")
    try:
        raw_quote_result = call_tool("twelvedata_GetQuote", {"params": {"symbol": symbol}})
        execution_log.append(f"[RAW] {str(raw_quote_result)[:200]}")
        quote_data = json.loads(raw_quote_result) if isinstance(raw_quote_result, str) else raw_quote_result
        most_recent_close_price_str = quote_data.get('close', '0.0')
        try:
            most_recent_close_price = float(most_recent_close_price_str)
        except ValueError:
            most_recent_close_price = 0.0
            execution_log.append(f"Warning: Could not convert most recent close price '{most_recent_close_price_str}' to float. Defaulting to 0.0.")
        execution_log.append(f"Extracted most recent closing price for {symbol}: {most_recent_close_price:.2f}")
    except Exception as e:
        execution_log.append(f"Error in Step 1 (twelvedata_GetQuote): {e}")
        return "\n".join(execution_log)

    # Step 2: Fetch daily price history for the last 5 days for AAPL
    execution_log.append(f"Step 2: Fetching daily price history for {symbol} for the last 5 days up to {end_date_for_history}.")
    try:
        raw_history_result = call_tool("twelvedata_GetTimeSeries", {
            "params": {
                "symbol": symbol,
                "interval": "1day",
                "outputsize": 5,
                "end_date": end_date_for_history
            }
        })
        execution_log.append(f"[RAW] {str(raw_history_result)[:200]}")
        history_data = json.loads(raw_history_result) if isinstance(raw_history_result, str) else raw_history_result

        historical_values = history_data.get('values', [])
        execution_log.append(f"Retrieved {len(historical_values)} historical daily values. Sample (first entry): {str(historical_values[:1])[:200]}")

        # Step 3: Identify the highest 'high' price from the historical data
        highest_5day_high = 0.0
        if historical_values:
            for entry in historical_values:
                high_price_str = entry.get('high', '0.0')
                try:
                    high_price = float(high_price_str)
                    if high_price > highest_5day_high:
                        highest_5day_high = high_price
                except ValueError:
                    execution_log.append(f"Warning: Could not convert high price '{high_price_str}' to float in historical data. Skipping this entry.")
        execution_log.append(f"Extracted highest 'high' price over the last 5 days: {highest_5day_high:.2f}")

        # Step 4: Compare and determine if the most recent closing price is within 1% of the 5-day high
        is_within_1_percent = False
        if highest_5day_high > 0:
            percentage_difference = abs((most_recent_close_price - highest_5day_high) / highest_5day_high) * 100
            if percentage_difference <= 1.0:
                is_within_1_percent = True

        final_output = (
            f"Most recent closing price for {symbol}: {most_recent_close_price:.2f}\n"
            f"Highest 'high' price in the last 5 days: {highest_5day_high:.2f}\n"
            f"Is the most recent closing price within 1% of the 5-day high? {'Yes' if is_within_1_percent else 'No'}"
        )
        execution_log.append(f"Final Analysis: {final_output}")

    except Exception as e:
        execution_log.append(f"Error in Step 2 or 3 (twelvedata_GetTimeSeries or processing): {e}")
        return "\n".join(execution_log)

    return "\n".join(execution_log)

